package org.jsoup.parser;

import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.nodes.Node;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

public class Parser_AllScenarios_Test {

    @Test
    @DisplayName("setTrackErrors(0) disables error tracking and isTrackErrors() returns false")
    public void test_TC04() {
        // Scenario TC04: boundary where maxErrors=0 should disable tracking path B1(>0?)->B3(=0)
        Parser parser = Parser.htmlParser();
        parser.setTrackErrors(0); // set to zero disables error tracking
        assertFalse(parser.isTrackErrors(), "Expected isTrackErrors() to be false when maxErrors=0");
        assertEquals(0, parser.getErrors().getMaxSize(), "Expected error list max size to be 0 when tracking disabled");
    }

    @Test
    @DisplayName("setTrackErrors(5) enables tracking up to 5 errors and isTrackErrors() returns true")
    public void test_TC05() {
        // Scenario TC05: positive boundary where maxErrors>0 takes B1(>0)->B2
        Parser parser = Parser.xmlParser();
        parser.setTrackErrors(5); // positive number should enable tracking
        assertTrue(parser.isTrackErrors(), "Expected isTrackErrors() to be true when maxErrors>0");
        assertEquals(5, parser.getErrors().getMaxSize(), "Expected error list max size to match set value");
    }

    @Test
    @DisplayName("setTrackPosition(true) and setTrackPosition(false) toggle position tracking flag")
    public void test_TC06() {
        // Scenario TC06: toggle flag true then false to cover both branches of setTrackPosition
        Parser parser = Parser.htmlParser();
        parser.setTrackPosition(true); // path B1(true)
        assertTrue(parser.isTrackPosition(), "Expected trackPosition true after setting true");
        parser.setTrackPosition(false); // path B2(false)
        assertFalse(parser.isTrackPosition(), "Expected trackPosition false after setting false");
    }

    @Test
    @DisplayName("newInstance() produces an independent Parser clone with same settings but separate errors list")
    public void test_TC07() {
        // Scenario TC07: clone independence; clone shares settings but errors lists are separate
        Parser p1 = Parser.htmlParser().setTrackErrors(3).setTrackPosition(true);
        Parser p2 = p1.newInstance(); // clone
        p2.setTrackErrors(1); // modify p2's errors
        assertNotSame(p1, p2, "Expected clone to be a different instance");
        assertEquals(p1.settings(), p2.settings(), "Expected cloned parser to share same settings");
        assertNotEquals(p1.getErrors().getMaxSize(), p2.getErrors().getMaxSize(),
                "Expected separate error lists so changes in clone do not affect original");
    }

    @Test
    @DisplayName("setTreeBuilder replaces TreeBuilder and propagates parser reference")
    public void test_TC08() throws Exception {
        // Scenario TC08: setter replaces builder and updates builder.parser field via reflection
        Parser parser = Parser.htmlParser();
        XmlTreeBuilder customBuilder = new XmlTreeBuilder();
        Parser returned = parser.setTreeBuilder(customBuilder);
        assertSame(parser, returned, "Expected setter to return same parser instance for chaining");
        assertSame(customBuilder, parser.getTreeBuilder(), "Expected parser to hold the new tree builder");
        // use reflection to access package-private field 'parser' in TreeBuilder
        Field parserField = customBuilder.getClass().getDeclaredField("parser");
        parserField.setAccessible(true);
        Object innerParser = parserField.get(customBuilder);
        assertSame(parser, innerParser, "Expected new builder.parser to reference the owning parser");
    }

    @Test
    @DisplayName("parseBodyFragment moves nodes correctly and loops removal and appendChild paths")
    public void test_TC09() {
        // Scenario TC09: exercise removal loop and append loop to order nodes into body
        String html = "<div>A</div><p>B</p>";
        String baseUri = "http://x/";
        Document doc = Parser.parseBodyFragment(html, baseUri);
        List<Node> children = doc.body().childNodes();
        assertEquals(2, children.size(), "Expected two child nodes in body after parsing");
        // first node should be <div>
        assertEquals("div", ((Element) children.get(0)).tagName(), "First child should be div");
        // second node should be <p>
        assertEquals("p", ((Element) children.get(1)).tagName(), "Second child should be p");
    }

    @Test
    @DisplayName("unescapeEntities processes numeric and named entities with inAttribute true/false")
    public void test_TC10() {
        // Scenario TC10: both attribute and non-attribute paths should unescape to same result
        String input = "&lt; &amp; &#65;";
        String out1 = Parser.unescapeEntities(input, true);  // path inAttribute=true
        String out2 = Parser.unescapeEntities(input, false); // path inAttribute=false
        assertEquals("< & A", out1, "Expected named and numeric entities unescaped correctly in attribute mode");
        assertEquals("< & A", out2, "Expected named and numeric entities unescaped correctly in data mode");
    }
}
